let user=localStorage.getItem('pp_user')?JSON.parse(localStorage.getItem('pp_user')):null;
let tab='pipeline';
let leads=[{id:1,n:'Sarah Johnson',e:'sarah@techstartup.io',c:'TechStartup IO',s:'new',sc:8,url:'https://techstartup.io'},{id:2,n:'Mike Chen',e:'mike@growthagency.co',c:'Growth Agency',s:'new',sc:7,url:'https://growthagency.co'},{id:3,n:'Lisa Wang',e:'lisa@enterprise.com',c:'Enterprise Co',s:'contacted',sc:9,url:'https://enterprise.com'},{id:4,n:'John Smith',e:'john@startupxyz.io',c:'StartupXYZ',s:'replied',sc:6,url:'https://startupxyz.io'},{id:5,n:'Emma Davis',e:'emma@digitalfirst.co',c:'Digital First',s:'meeting',sc:8,url:'https://digitalfirst.co'}];
let acts=[];
let competitors=[{n:'competitor1.com'},{n:'competitor2.io'}];
let reports=[];
let running=false;

function toast(msg){var t=document.getElementById('toast');if(t){t.innerHTML='<div class="toast">'+msg+'</div>';t.style.display='block';setTimeout(function(){t.style.display='none'},3000)}}

function rnd(){var cols=['new','contacted','replied','meeting'];var h='<div class="page-header"><h2 class="page-title">Pipeline</h2><div><button class="btn-outline" onclick="doExport()">Export</button> <button class="btn" onclick="showAddLead()">+ Add Lead</button></div></div><div class="stats-grid"><div class="stat-card"><div class="stat-value">'+leads.length+'</div><div class="stat-label">Total Leads</div></div><div class="stat-card"><div class="stat-value">'+leads.filter(function(l){return l.s==='new'}).length+'</div><div class="stat-label">New Today</div></div><div class="stat-card"><div class="stat-value">'+leads.filter(function(l){return l.s==='contacted'}).length+'</div><div class="stat-label">Contacted</div></div><div class="stat-card"><div class="stat-value">'+leads.filter(function(l){return l.s==='replied'}).length+'</div><div class="stat-label">Replied</div></div><div class="stat-card"><div class="stat-value">'+leads.filter(function(l){return l.s==='meeting'}).length+'</div><div class="stat-label">Meetings</div></div><div class="stat-card"><div class="stat-value">'+acts.length+'</div><div class="stat-label">Tasks</div></div></div><div class="pipeline-grid">';cols.forEach(function(st){h+='<div class="pipeline-col"><h4>'+st+' ('+leads.filter(function(l){return l.s===st}).length+')</h4>';leads.filter(function(l){return l.s===st}).forEach(function(l){h+='<div class="lead-card" data-id="'+l.id+'"><div class="lead-name">'+l.n+(l.sc>=8?'<span class="badge badge-neo">⭐</span>':'')+'</div><div class="lead-company">'+l.c+'</div><div class="lead-score">Score: '+l.sc+'/10</div></div>'});h+='</div>'});h+='</div>';return h}

function rendAgt(){var btn=running?'disabled':'';return '<h2 class="page-title">Your AI Agents</h2><p style="color:#888;margin-bottom:2rem">Three agents working 24/7</p><div class="agent-card"><div class="agent-header"><div class="agent-info"><span class="agent-emoji">🦅</span><span class="agent-name">Neo — Lead Agent</span></div><span class="agent-status">● '+(running?'Running...':'Active')+'</span></div><p class="agent-desc">Finds qualified leads and drafts personalized outreach.</p><div class="agent-stats"><div class="agent-stat"><div class="agent-stat-value">'+leads.filter(function(l){return l.s==='new'}).length+'</div><div class="agent-stat-label">Leads today</div></div><div class="agent-stat"><div class="agent-stat-value">'+leads.filter(function(l){return l.s==='new'}).length+'</div><div class="agent-stat-label">Outreach ready</div></div><div class="agent-stat"><div class="agent-stat-value">8.5</div><div class="agent-stat-label">Avg Score</div></div></div><button class="run-btn" onclick="runNeo()" '+btn+'>'+(running?'Running...':'Run Now')+'</button></div><div class="agent-card"><div class="agent-header"><div class="agent-info"><span class="agent-emoji">🗺️</span><span class="agent-name">Atlas — Research</span></div><span class="agent-status">● '+(running?'Running...':'Active')+'</span></div><p class="agent-desc">Monitors competitors and gathers market intelligence.</p><div class="agent-stats"><div class="agent-stat"><div class="agent-stat-value">'+competitors.length+'</div><div class="agent-stat-label">Competitors</div></div><div class="agent-stat"><div class="agent-stat-value">24h</div><div class="agent-stat-label">Last Check</div></div><div class="agent-stat"><div class="agent-stat-value">0</div><div class="agent-stat-label">Changes</div></div></div><button class="run-btn" onclick="runAtlas()" '+btn+'>'+(running?'Running...':'Run Now')+'</button></div><div class="agent-card"><div class="agent-header"><div class="agent-info"><span class="agent-emoji">🛸</span><span class="agent-name">Orbit — Operations</span></div><span class="agent-status">● '+(running?'Running...':'Active')+'</span></div><p class="agent-desc">Generates reports and tracks performance.</p><div class="agent-stats"><div class="agent-stat"><div class="agent-stat-value">'+reports.length+'</div><div class="agent-stat-label">Reports</div></div><div class="agent-stat"><div class="agent-stat-value">'+acts.length+'</div><div class="agent-stat-label">Tasks Done</div></div><div class="agent-stat"><div class="agent-stat-value">99%</div><div class="agent-stat-label">Uptime</div></div></div><button class="run-btn" onclick="runOrbit()" '+btn+'>'+(running?'Running...':'Generate Report')+'</button></div>'}

function rendRep(){var h='<h2 class="page-title">Reports</h2><p style="color:#888;margin-bottom:2rem">Generated by Orbit</p>';if(reports.length===0){h+='<p style="color:#666;margin-bottom:1rem">No reports yet.</p><button class="btn" onclick="runOrbit()">Generate Report Now</button>'}else{reports.forEach(function(r){h+='<div class="report-card"><div class="report-header"><span class="report-title">'+r.t+'</span><span class="report-date">'+r.d+'</span></div></div>'})}return h}

function rendAct(){var h='<h2 class="page-title">Activity</h2><p style="color:#888;margin-bottom:2rem">Recent agent actions</p><div class="activity-list">';if(acts.length===0){h+='<p style="color:#666">No activity yet. Run an agent to see activity.</p>'}else{acts.forEach(function(a){h+='<div class="activity-item"><div class="activity-info"><span>'+a.i+'</span><span class="activity-text">'+a.d+'</span></div><span class="activity-time">'+a.t+'</span></div>'})}h+='</div>';return h}

function rendAI(){return '<h2 class="page-title">Ask AI</h2><div class="chat-container"><div class="suggested-prompts"><span class="prompt-chip" onclick="askAI(\'How many leads?\')">How many leads?</span><span class="prompt-chip" onclick="askAI(\'Which to contact?\')">Which to contact?</span><span class="prompt-chip" onclick="askAI(\'What are agents doing?\')">What are agents doing?</span></div><p style="color:#666;text-align:center;padding:2rem">Click a prompt or type below</p><div class="chat-input-area"><input type="text" class="chat-input" placeholder="Ask anything..." onkeypress="if(event.key===\'Enter\'){askAI(this.value);this.value=\'\'}"><button class="chat-send" onclick="askAI(document.querySelector(\'.chat-input\').value)">Send</button></div></div>'}

function rendSet(){var h='<h2 class="page-title">Settings</h2><div class="form-group"><label class="form-label">Your Name</label><input type="text" class="form-input" value="Deva"></div><div class="form-group"><label class="form-label">Business Name</label><input type="text" class="form-input" value="PPVentures"></div><div class="form-group"><label class="form-label">Target Niche</label><input type="text" class="form-input" value="Small businesses in India"></div><div class="form-group"><label class="form-label">Competitors</label>';competitors.forEach(function(c){h+='<div class="comp-item"><span>'+c.n+'</span></div>'});h+='</div>';return h}

function openLead(id){var l=leads.find(function(x){return x.id===id});if(!l)return;var ins=l.n.split(' ').map(function(w){return w[0]}).join('');var h='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal"><div class="modal-header"><button class="modal-close" onclick="closeModal()">×</button></div><div class="lead-detail-header"><div class="lead-avatar">'+ins+'</div><div><div class="lead-detail-name">'+l.n+'</div><div class="lead-detail-company">'+l.c+'</div><span class="lead-detail-status">'+l.s+'</span></div></div><div class="detail-section"><h4>Contact Info</h4><div class="detail-row"><span class="detail-label">Email</span><span class="detail-value">'+l.e+'</span></div><div class="detail-row"><span class="detail-label">Website</span><span class="detail-value"><a href="'+l.url+'" target="_blank" style="color:#10b981">'+l.url+'</a></span></div></div><div class="detail-section"><h4>Lead Score</h4><div class="score-bar"><div class="score-fill" style="width:'+(l.sc*10)+'%"></div></div><div class="score-text">'+l.sc+'/10</div></div><div class="detail-section"><h4>Actions</h4><div class="status-btns">'+(l.s!=='contacted'?'<button class="status-btn" onclick="moveLead('+l.id+',\'contacted\')">→ Contacted</button>':'')+(l.s!=='replied'?'<button class="status-btn" onclick="moveLead('+l.id+',\'replied\')">→ Replied</button>':'')+(l.s!=='meeting'?'<button class="status-btn" onclick="moveLead('+l.id+',\'meeting\')">→ Meeting</button>':'')+'<button class="status-btn delete" onclick="delLead('+l.id+')">🗑️ Delete</button></div></div></div></div>';document.getElementById('modal').innerHTML=h}

function closeModal(){document.getElementById('modal').innerHTML=''}

function moveLead(id,st){leads=leads.map(function(l){return l.id===id?Object.assign({},l,{s:st}):l});var l=leads.find(function(x){return x.id===id});acts=[{i:'➡️',d:l.n+' moved to '+st,t:'Just now'}].concat(acts);toast(l.n+' → '+st);render()}

function delLead(id){var l=leads.find(function(x){return x.id===id});leads=leads.filter(function(x){return x.id!==id});acts=[{i:'🗑️',d:'Deleted: '+l.n,t:'Just now'}].concat(acts);toast('Lead deleted');render()}

function showAddLead(){document.getElementById('modal').innerHTML='<div class="modal-overlay" onclick="if(event.target===this)closeModal()"><div class="modal"><div class="modal-header"><h3>Add Lead</h3><button class="modal-close" onclick="closeModal()">×</button></div><div class="form-group"><label class="form-label">Name</label><input type="text" id="add-n" class="form-input"></div><div class="form-group"><label class="form-label">Company</label><input type="text" id="add-c" class="form-input"></div><div class="form-group"><label class="form-label">Email</label><input type="email" id="add-e" class="form-input"></div><div class="form-group"><label class="form-label">Website</label><input type="text" id="add-u" class="form-input"></div><button class="btn" onclick="addLead()">Add Lead</button></div></div>'}

function addLead(){var n=document.getElementById('add-n').value;var c=document.getElementById('add-c').value;var e=document.getElementById('add-e').value;var u=document.getElementById('add-u').value;if(n&&c){leads=[{id:Date.now(),n:n,c:c,e:e||'',s:'new',sc:5,url:u||''}].concat(leads);acts=[{i:'➕',d:'Added: '+n,t:'Just now'}].concat(acts);closeModal();toast('Lead added!');render()}}

function doExport(){var csv='Name,Company,Email,Score,Status\n'+leads.map(function(l){return l.n+','+l.c+','+l.e+','+l.sc+','+l.s}).join('\n');var a=document.createElement('a');a.href='data:text/csv,'+encodeURIComponent(csv);a.download='ppventures-leads.csv';a.click();toast('CSV exported!')}

function askAI(q){var r='';if(q.indexOf('how many')>-1||q.indexOf('lead')>-1){r='You have '+leads.length+' leads: '+leads.filter(function(l){return l.s==='new'}).length+' new, '+leads.filter(function(l){return l.s==='contacted'}).length+' contacted, '+leads.filter(function(l){return l.s==='meeting'}).length+' meetings.'}else if(q.indexOf('contact')>-1||q.indexOf('prioritize')>-1){var top=leads.filter(function(l){return l.s==='new'}).sort(function(a,b){return b.sc-a.sc}).slice(0,3);r=top.length?'Contact these first:\n'+top.map(function(l,i){return(i+1)+'. '+l.n+' ('+l.sc+'/10)'}).join('\n'):'No new leads!'}else if(q.indexOf('agent')>-1||q.indexOf('working')>-1){r='🦅 Neo: '+leads.filter(function(l){return l.s==='new'}).length+' new leads\n🗺️ Atlas: '+competitors.length+' competitors\n🛸 Orbit: '+reports.length+' reports\n\nAll active!'}else{r='Try: "How many leads?", "Which to contact?", "What are agents doing?"'}alert(r)}

async function runNeo(){if(running)return;running=true;render();toast('🦅 Neo finding leads...');await new Promise(function(r){setTimeout(r,1500)});var nl=[{id:Date.now(),n:'Priya Sharma',e:'priya@digitalscale.in',c:'DigitalScale Solutions',s:'new',sc:8,url:'https://digitalscale.in'},{id:Date.now()+1,n:'Rahul Mehta',e:'rahul@cloudbridge.io',c:'CloudBridge Tech',s:'new',sc:7,url:'https://cloudbridge.io'}];leads=nl.concat(leads);acts=[{i:'🦅',d:'Neo found '+nl.length+' new leads',t:'Just now'}].concat(acts);running=false;toast('✅ Found '+nl.length+' new leads!');render()}

async function runAtlas(){if(running)return;running=true;render();toast('🗺️ Atlas researching...');await new Promise(function(r){setTimeout(r,1500)});acts=[{i:'🗺️',d:'Atlas completed competitor research',t:'Just now'}].concat(acts);running=false;toast('✅ Research complete!');render()}

async function runOrbit(){if(running)return;running=true;render();toast('🛸 Orbit generating report...');await new Promise(function(r){setTimeout(r,1500)});var d=new Date().toLocaleDateString('en-US',{month:'short',day:'numeric'});reports=[{t:'Daily Report - '+d,d:'Just now'}].concat(reports);acts=[{i:'🛸',d:'Orbit generated daily report',t:'Just now'}].concat(acts);running=false;toast('✅ Report generated!');render()}

function login(e){e.preventDefault();user={e:document.getElementById('em').value};localStorage.setItem('pp_user',JSON.stringify(user));render()}
function logout(){user=null;localStorage.removeItem('pp_user');render()}

function render(){var d=document.getElementById('app');if(!user){d.innerHTML='<div class="login-page"><div class="login-container"><h1 class="login-title"><span>◆ PP</span>Ventures</h1><p class="login-subtitle">Client Dashboard</p><form onsubmit="login(event)"><input type="email" id="em" class="login-input" placeholder="Email" required><input type="password" id="pw" class="login-input" placeholder="Password" required minlength="6"><button type="submit" class="login-btn">Sign In</button></form></div></div>';return}
var uname=user&&user.e?user.e:'User';d.innerHTML='<div class="header"><h1><span>◆ PP</span>Ventures</h1><div class="header-right"><span class="trial-badge">🔄 Trial — 14 days left</span><span>'+uname+'</span><button class="logout" onclick="logout()">Logout</button></div></div><div class="main"><div class="sidebar"><button class="nav-item '+(tab==='pipeline'?'active':'')+'" onclick="tab=\'pipeline\';render()">🎯 Pipeline</button><button class="nav-item '+(tab==='agents'?'active':'')+'" onclick="tab=\'agents\';render()">🤖 Agents</button><button class="nav-item '+(tab==='reports'?'active':'')+'" onclick="tab=\'reports\';render()">📊 Reports</button><button class="nav-item '+(tab==='activity'?'active':'')+'" onclick="tab=\'activity\';render()">📝 Activity</button><button class="nav-item '+(tab==='ai'?'active':'')+'" onclick="tab=\'ai\';render()">💬 Ask AI</button><button class="nav-item '+(tab==='settings'?'active':'')+'" onclick="tab=\'settings\';render()">⚙️ Settings</button></div><div class="content">'+(tab==='pipeline'?rnd():tab==='agents'?rendAgt():tab==='reports'?rendRep():tab==='activity'?rendAct():tab==='ai'?rendAI():rendSet())+'</div></div>'}

function init(){document.getElementById('app').addEventListener('click',function(e){var lc=e.target.closest('.lead-card');if(lc){var id=parseInt(lc.getAttribute('data-id'));if(id)openLead(id)}});render()}

init();
